import{_ as e,o,c as d,ai as r}from"./chunks/framework.CaiDwmc7.js";const p=JSON.parse('{"title":"PrismController","description":"The central orchestrator — responsibilities, extension state model, and events.","frontmatter":{"title":"PrismController","description":"The central orchestrator — responsibilities, extension state model, and events.","outline":[2,3]},"headers":[],"relativePath":"vscode/controller.md","filePath":"vscode/controller.md","lastUpdated":0}'),s={name:"vscode/controller.md"};function n(c,t,a,i,l,h){return o(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="core-orchestrator-—-prismcontroller" tabindex="-1">Core Orchestrator — PrismController <a class="header-anchor" href="#core-orchestrator-—-prismcontroller" aria-label="Permalink to “Core Orchestrator — PrismController”">​</a></h1><p>The <code>PrismController</code> is the central hub that ties together all extension functionality.</p><h2 id="responsibilities" tabindex="-1">Responsibilities <a class="header-anchor" href="#responsibilities" aria-label="Permalink to “Responsibilities”">​</a></h2><table tabindex="0"><thead><tr><th>Area</th><th>Components</th><th>Description</th></tr></thead><tbody><tr><td><strong>State</strong></td><td><code>updateState()</code>, <code>PrismExtensionState</code></td><td>Atomic state updates, broadcast to all webview subscribers via gRPC streams</td></tr><tr><td><strong>Workflow</strong></td><td><code>WorkflowStateMachine</code></td><td>Phase transitions with validation (Idle → Research → Plan → Implement → Validate)</td></tr><tr><td><strong>Stories</strong></td><td><code>StoriesManager</code></td><td>Load/save <code>stories.json</code>, resolve dependencies, track progress</td></tr><tr><td><strong>Chat</strong></td><td><code>ClaudeRunner</code>, tool handlers</td><td>Spawn Claude CLI with <code>--output-format stream-json</code>, handle tool use recursively</td></tr><tr><td><strong>Spectrum</strong></td><td><code>SpectrumEngine</code>, <code>SpectrumRunner</code></td><td>Execution loop state machine, per-iteration CLI subprocess management</td></tr><tr><td><strong>Skills</strong></td><td><code>ModeBridge</code>, <code>PluginBridge</code></td><td>Switch between SDK chat and CLI plugin mode, route skill invocations</td></tr><tr><td><strong>Files</strong></td><td><code>PrismWatcher</code></td><td>Monitor <code>.prism/</code> directory for changes, fire <code>onDidChangeFile</code> events</td></tr><tr><td><strong>Office</strong></td><td><code>AgentBridge</code></td><td>Connect Spectrum sessions to Office agent characters</td></tr></tbody></table><h2 id="extension-state-model-prismextensionstate" tabindex="-1">Extension State Model (<code>PrismExtensionState</code>) <a class="header-anchor" href="#extension-state-model-prismextensionstate" aria-label="Permalink to “Extension State Model (PrismExtensionState)”">​</a></h2><p>The full state is broadcast to all webview subscribers on every update:</p><table tabindex="0"><thead><tr><th>Category</th><th>Fields</th><th>Description</th></tr></thead><tbody><tr><td><strong>Workspace</strong></td><td><code>hasPrismDir</code>, <code>hasStoriesJson</code>, <code>prismDir</code>, <code>storiesPath</code></td><td><code>.prism/</code> detection</td></tr><tr><td><strong>Workflow</strong></td><td><code>workflowPhase</code>, <code>workflowContext</code></td><td>Current phase + active document/story</td></tr><tr><td><strong>Stories</strong></td><td><code>stories[]</code>, <code>plan</code>, <code>completedCount</code>, <code>remainingCount</code></td><td>Story data + progress</td></tr><tr><td><strong>Chat</strong></td><td><code>chatMessages[]</code>, <code>isChatStreaming</code>, <code>hasActiveTask</code>, <code>pendingApprovalToolUseId</code></td><td>Conversation state</td></tr><tr><td><strong>CLI</strong></td><td><code>chatMode</code> (<code>sdk</code>/<code>plugin</code>), <code>activePluginSkill</code>, <code>hasClaudeCli</code></td><td>CLI bridge state</td></tr><tr><td><strong>Spectrum</strong></td><td><code>executionState</code>, <code>currentIteration</code>, <code>currentStoryId</code>, <code>progress</code>, <code>elapsedMs</code>, <code>consecutiveErrors</code>, <code>lastSignalType</code>, <code>recentActivities[]</code>, <code>logs[]</code></td><td>Full execution state</td></tr><tr><td><strong>Office</strong></td><td><code>office.enabled</code>, <code>office.agentCount</code>, <code>office.activeAgents[]</code></td><td>Agent tracking</td></tr><tr><td><strong>Config</strong></td><td><code>defaultModel</code>, <code>planningModel</code></td><td>Model selections</td></tr></tbody></table><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to “Events”">​</a></h2><table tabindex="0"><thead><tr><th>Event</th><th>Trigger</th><th>Consumers</th></tr></thead><tbody><tr><td><code>onDidChangeFile</code></td><td><code>.prism/</code> file added/changed/deleted</td><td>Tree providers</td></tr><tr><td><code>onDidChangeState</code></td><td>Any state update</td><td>Status bar, webviews</td></tr><tr><td><code>onDidStartSession</code></td><td>Claude session begins</td><td>AgentBridge</td></tr><tr><td><code>onDidUpdateStory</code></td><td>Story status changes</td><td>Stories tree</td></tr><tr><td><code>onDidEndSpectrumStory</code></td><td>Story iteration completes</td><td>Monitor history</td></tr></tbody></table>',9)])])}const m=e(s,[["render",n]]);export{p as __pageData,m as default};
